-- 9003_Master_Rebuild.sql
-- Full from-scratch rebuild — every table, view, seed row, and RLS
-- policy in one file, in correct dependency order. Covers all 13
-- tables (the original 8, plus the 5-table Attendance module added
-- later) and all 12 views. Generated by literal concatenation of the
-- individual verified source files, not hand-assembled from memory —
-- regenerate this file fresh whenever those source files change,
-- rather than hand-patching it directly.
--
-- Regenerated this pass specifically to pick up two fixes verified
-- against the live 9002 snapshot: personal_profile.short_name (present,
-- positioned at the end of the column list, matching live's actual
-- physical order) and attendance_log.oracle_updated's default
-- (true, not false).
--
-- Run this top-to-bottom on a genuinely empty database to stand up a
-- complete copy of PWMS AC's schema, Attendance module included. Load
-- your data export separately afterward (this file has real seed data
-- for every table, since all 13 now have a seed file — but it's not a
-- substitute for your actual live data if you're restoring, not
-- starting fresh).
--
-- 9010_Attendance_Master_Rebuild.sql is retired now that this file
-- covers everything — safe to delete.

-- ==========================================================================
-- SOURCE: 1010_Create_Portfolio.sql
-- ==========================================================================
-- 1010_Create_Portfolio.sql

create table if not exists portfolio (

    portfolio_id uuid
        primary key
        default gen_random_uuid(),

    portfolio_name text
        not null,

    portfolio_type text
        not null,

    description text,

    enabled boolean
        not null
        default true,

    display_order integer
        default 100,

    created_at timestamptz
        not null
        default now(),

    created_by text
        not null
        default 'System',

    updated_at timestamptz
        not null
        default now(),

    updated_by text
        not null
        default 'System'
);

create unique index if not exists
uq_portfolio_name
on portfolio(portfolio_name);

create index if not exists
idx_portfolio_name
on portfolio(portfolio_name);

create index if not exists
idx_portfolio_enabled
on portfolio(enabled);

grant all on table portfolio to anon;
grant all on table portfolio to authenticated;


