-- SOURCE: 2041_View_ReviewOpenActivities.sql
-- ==========================================================================
-- 2041_View_ReviewOpenActivities.sql

drop view if exists vw_review_open_activities;

create view vw_review_open_activities as

select

    activity_id,
    activity_name,
    status,
    target_date,
    portfolio_name,
