-- SOURCE: 2061_View_ReviewRecentLogs.sql
-- ==========================================================================
-- 2061_View_ReviewRecentLogs.sql

drop view if exists vw_review_recent_logs;

create view vw_review_recent_logs as

select *
from vw_task_log_details
order by task_date desc, start_time desc;

grant select on vw_review_recent_logs to anon;
grant select on vw_review_recent_logs to authenticated;


-- ==========================================================================
-- SOURCE: 2062_View_ReviewTimeSummary.sql
-- ==========================================================================
-- 2062_View_ReviewTimeSummary.sql

drop view if exists vw_review_time_summary;

create view vw_review_time_summary as

select

    coalesce(
        sum(
            case
                when task_date = current_date
                then minutes_spent
                else 0
            end
        ),
        0
    ) as today_minutes,

    coalesce(
        sum(
            case
                when task_date >= date_trunc('week', current_date)::date
                then minutes_spent
                else 0
            end
        ),
        0
    ) as week_minutes,

    coalesce(
        sum(
            case
                when task_date >= date_trunc('month', current_date)::date
                then minutes_spent
                else 0
            end
        ),
        0
    ) as month_minutes

from task_log;

grant select on vw_review_time_summary to anon;
grant select on vw_review_time_summary to authenticated;


-- ==========================================================================
-- SOURCE: 2071_View_ReviewPortfolioTime.sql
-- ==========================================================================
-- 2071_View_ReviewPortfolioTime.sql
-- NOTE: this view only joins task_log -> activity -> milestone. It has
-- no awareness of the newer task_log.todo_id path, so hours logged
-- against a ToDo (most current logging) are miscounted into
-- "Standalone Activities." Left exactly as-is per instruction, matching
-- live behavior precisely rather than silently correcting it here.

drop view if exists vw_review_portfolio_time;

create view vw_review_portfolio_time as

select

    coalesce(p.portfolio_name, 'Standalone Activities') as portfolio_name,

    round(sum(t.minutes_spent) / 60.0, 1) as hours_spent

from task_log t

left join activity a
    on t.activity_id = a.activity_id

left join milestone m
    on a.milestone_id = m.milestone_id

left join project pr
    on m.project_id = pr.project_id

left join portfolio p
    on pr.portfolio_id = p.portfolio_id

group by portfolio_name

order by hours_spent desc;

grant select on vw_review_portfolio_time to anon;
grant select on vw_review_portfolio_time to authenticated;


-- ==========================================================================
-- SOURCE: 2072_View_PayrollMonth.sql
-- ==========================================================================
-- 2072_View_PayrollMonth.sql
-- Cross-table report, not flavored by a single table — matches an
-- attendance_log row to whichever employment_history stint was active
-- on that date, then computes the payroll month/year using THAT
-- stint's own cycle days (not a single global rule), since a future
-- employer could run a different cycle entirely.
--
-- Rarely used — mainly relevant around a Last Working Day. Left as its
-- own separate view rather than folded into the everyday attendance
-- pages, per instruction.

drop view if exists vw_payroll_month;

create view vw_payroll_month as

select

    al.log_date,
    al.code,
    al.description,
    al.hr_type_frozen,

    eh.employer_name,
    eh.payroll_cycle_start_day,
    eh.payroll_cycle_end_day,

    case
        when extract(day from al.log_date) >= eh.payroll_cycle_start_day
        then case
                when extract(month from al.log_date) = 12 then 1
                else extract(month from al.log_date) + 1
             end
        else extract(month from al.log_date)
    end as payroll_month,

    case
        when extract(day from al.log_date) >= eh.payroll_cycle_start_day
             and extract(month from al.log_date) = 12
        then extract(year from al.log_date) + 1
        else extract(year from al.log_date)
    end as payroll_year

from attendance_log al

left join employment_history eh
    on al.log_date >= eh.start_date
    and (eh.end_date is null or al.log_date <= eh.end_date);

grant select on vw_payroll_month to anon;
grant select on vw_payroll_month to authenticated;


-- ==========================================================================
-- SOURCE: 2100_View_CurrentEmployment.sql
-- ==========================================================================
-- 2100_View_CurrentEmployment.sql
-- Convenience view — "give me my current job" without every page
-- needing to repeat the end_date IS NULL filter itself.

drop view if exists vw_current_employment;

create view vw_current_employment as

select *
from employment_history
where end_date is null
order by start_date desc
limit 1;

grant select on vw_current_employment to anon;
grant select on vw_current_employment to authenticated;


-- ==========================================================================
-- SOURCE: 2130_View_AttendanceLog.sql
-- ==========================================================================
-- 2130_View_AttendanceLog.sql
-- Plain ordered passthrough — kept consistent with the rest of the app's
-- convention of always reading through a view, even for a 1:1 relationship.

drop view if exists vw_attendance_log;

create view vw_attendance_log as

select *
from attendance_log
order by log_date desc;

grant select on vw_attendance_log to anon;
grant select on vw_attendance_log to authenticated;


